mapper.select:
select id, module, operation, entity_type, entity_id, entity_name,
       description, old_value, new_value,
       operator_id, operator_name, ip_address, user_agent,
       status, error_msg, execution_time, created_at
from operation_logs


        and module = #{module}


        and entity_type = #{entityType}


        and entity_id = #{entityId}


        and operator_id = #{operatorId}


order by created_at desc

select id, module, operation, entity_type, entity_id, entity_name,
       description, old_value, new_value,
       operator_id, operator_name, ip_address, user_agent,
       status, error_msg, execution_time, created_at
from operation_logs


        and module = #{module}


        and operation = #{operation}


        and status = #{status}


order by created_at desc
